mapper.select:
SELECT id, visitor_name, visitor_id_card, visitor_phone, visit_user_id, visit_user_name, visit_user_room, visit_type, check_in_time, check_out_time, visitor_status, gate_operator, create_by, create_time, update_by, update_time, remark
FROM community_visitor
WHERE visitor_name LIKE CONCAT('%', #{visitorName}, '%')
  AND visitor_id_card = #{visitorIdCard}
  AND visitor_phone = #{visitorPhone}
  AND visit_user_id = #{visitUserId}
  AND visit_user_name LIKE CONCAT('%', #{visitUserName}, '%')
  AND visit_user_room = #{visitUserRoom}
  AND visit_type = #{visitType}
  AND check_in_time = #{checkInTime}
  AND check_out_time = #{checkOutTime}
  AND visitor_status = #{visitorStatus}
  AND gate_operator = #{gateOperator}

SELECT id, visitor_name, visitor_id_card, visitor_phone, visit_user_id, visit_user_name, visit_user_room, visit_type, check_in_time, check_out_time, visitor_status, gate_operator, create_by, create_time, update_by, update_time, remark
FROM community_visitor
WHERE id = #{id}
